  List ents=new ArrayList();
  IdentityService idSvc = new IdentityService(context);
  List appList=new ArrayList();
  appList=context.getObjects(Application.class);  

  String active="\"group.active\""+":"+ "\"true\"";
  // return a;
  int count = 0;
  int entcount=0;

  String url =null;
  String user=null;
  String password=null;
  String strPassword=null;
  String clientId=null;
  String ClientSecret=null;
  String strClientSec=null;
  Application application = context.getObjectByName(Application.class,"IdentityIQ for ServiceNow Service Desk");

  if(null!=application){
    url = application.getAttributeValue("url");    
    user=application.getAttributeValue("username");
    password=application.getAttributeValue("password");

    if(password!=null){
      strPassword=context.decrypt(password);
    }
  }

  String fileName = "\\\\ANDC1WAPP0147.ds.sjhs.com\\AppAggregation\\SnowAssignmentGroupReport-10-01-2024.csv";

  BufferedWriter outFile = new BufferedWriter(new FileWriter(fileName));

  //Write header

  outFile.write("Entitlement$Is Requestable$Application$Assignment Group$ Assignment Group Display Name$Is Group Active$Group Members Exists?$GroupMembers in Snow");
  outFile.newLine();
  outFile.flush();

  String groupActive=null;
  String url=null;
  Application application = context.getObjectByName(Application.class,"IdentityIQ for ServiceNow Service Desk");

  if(null!=application){
    url = application.getAttributeValue("url");    
    user=application.getAttributeValue("username");
    password=application.getAttributeValue("password");

    if(password!=null){
      strPassword=context.decrypt(password);
    }
  }


  try{
    for(Application app:appList){
      if(app.getType()!=null && app.getType().equalsIgnoreCase("DelimitedFile")){
        QueryOptions qo = new QueryOptions();
        qo.addFilter(Filter.eq("application.name",app.getName()));

        for(ManagedAttribute ent: context.getObjects(ManagedAttribute.class, qo)){


          String appName=ent.getApplication().getName();

          count++;

          if(ent.getAttributes()!=null){
            String assignementGrpId=ent.getAttributes().get("snowAssignmentGroup");
            String assignementGrpName=ent.getAttributes().get("snowAssignmentGroupName");
            if(assignementGrpId!=null){
             String newUrl=url+"/api/now/table/sys_user_grmember?sysparm_query=group.sys_id="+assignementGrpId+"&sysparm_fields=user.user_name,group.name,group.active";
//String newUrl="https://ascensionprod.service-now.com/api/now/table/sys_user_grmember?sysparm_query=group.sys_id=5c30835f1bc0acd47b74ea4fad4bcb8d&sysparm_fields=user.user_name,group.name,group.active";
              String encoding = Base64.getEncoder().encodeToString((user + ":" + strPassword).getBytes());


              URL url111 = new URL(newUrl);
              HttpURLConnection connection = (HttpURLConnection)url111.openConnection();
              connection.setRequestProperty("Host", "ascensionprod.service-now.com");
              connection.setRequestProperty("Authorization", String.format("Basic %s", encoding));
              connection.setRequestMethod("GET");
              // connection.setRequestProperty("Connection", "Keep-Alive");
              connection.setRequestProperty("Accept", "application/json");
              connection.setRequestProperty("Content-Type", "application//json");
              connection.setRequestProperty("Cookie", "BIGipServerpool_ascensiontrain=3188c261607f4bd8a5a4b17d8ec073dc; JSESSIONID=DBCA2A94FFB9D5AA731A461645CA4B58; glide_session_store=EA0B10B197BB155060E076F11153AF41; glide_user_route=glide.8d86e848bae3eb1b830f6867d7136fbe");
              connection.setRequestProperty("Content-Language", "en-US");
              //  connection.setUseCaches(false);
              connection.setDoInput(true);
              // return connection.getResponseCode();


              if (connection.getResponseCode() == 200) {

                String groupActive=null;
                BufferedReader reader = new BufferedReader(new InputStreamReader(connection.getInputStream()));
                String line = null;
                StringWriter out = new StringWriter(connection.getContentLength() > 0 ? connection.getContentLength() : 2048);
                while ((line = reader.readLine()) != null) {
                  out.append(line);
                }
                String response = out.toString();
                // log.error(response);
               // return response;
                if(response!=null){
                  /*if(response.contains(active)){
                    groupActive="true";
                  }else{
                    groupActive="false";
                  }*/

                  groupActive="false";
                  String groupMembers=null;
                  String users=null;
                  String groupMemberExist="N";
                  String userName="\"user.user_name\""+":";
                  String activeGroup="\"group.active\""+":";
                  if(response.contains(",")){

                    String[] strUserArr=response.split(",");
                    for(String strUserVals:strUserArr){
                      if(strUserVals.contains("group.active")){
                        String IsActive=strUserVals.replaceAll(activeGroup, "");
                        if(IsActive!=null){
                        groupActive=IsActive;
                        }
                        
                      }
                      if(strUserVals.contains("user.user_name")){
                        users=strUserVals.replaceAll(userName, "");
                        if(users!=null){


                          if(groupMembers==null){
                            groupMembers=users;
                          }else{
                            groupMembers=groupMembers+" | "+users;                 
                          }
                        }
                      }
                    }
                  }
                  if(groupMembers!=null){
                    groupMembers=groupMembers.replaceAll("}","");
                    groupMemberExist="Y";
                  }

//return ent.getValue()+"$"+ent.isRequestable()+"$"+ent.getApplication().getName()+"$"+assignementGrpId+"$"+assignementGrpName+"$"+groupActive+"$"+groupMemberExist+"$"+groupMembers;
                  outFile.write(ent.getValue()+"$"+ent.isRequestable()+"$"+ent.getApplication().getName()+"$"+assignementGrpId+"$"+assignementGrpName+"$"+groupActive+"$"+groupMemberExist+"$"+groupMembers);
                  outFile.newLine();
                  outFile.flush(); 
                }else{
                  outFile.write(ent.getValue()+"$"+ent.isRequestable()+"$"+ent.getApplication().getName()+"$"+assignementGrpId+"$"+assignementGrpName+"$$null$no response");
                  outFile.newLine();
                  outFile.flush(); 

                }

              }
              else{

                outFile.write(ent.getValue()+"$"+ent.isRequestable()+"$"+ent.getApplication().getName()+"$"+assignementGrpId+"$"+assignementGrpName+"$$null$no response");
                outFile.newLine();
                outFile.flush();
              }
            }else{

              outFile.write(ent.getValue()+"$"+ent.isRequestable()+"$"+ent.getApplication().getName()+"$null$null$null$null$null");
              outFile.newLine();
              outFile.flush();
            }

          }else{

            outFile.write(ent.getValue()+"$"+ent.isRequestable()+"$"+ent.getApplication().getName()+"$null$null$null$null$null");
            outFile.newLine();
            outFile.flush();
          }

          if ((count % 1000) == 0) {
            // context.decache();
            // log.error("Count: "+count); 
          }

        }


      }
    }

    if(null!=outFile){
      outFile.close();
    }

    return count;

  }catch(Exception e){

    log.error("snow test connection error:::"+e.printStackTrace());
    throw e;      
  }
